import{_ as r,o as t,c as a,a2 as o}from"./chunks/framework.BXL42d4u.js";const p=JSON.parse('{"title":"About VTKFortran","description":"","frontmatter":{"title":"About VTKFortran"},"headers":[],"relativePath":"guide/index.md","filePath":"guide/index.md"}'),n={name:"guide/index.md"};function i(s,e,l,d,h,u){return t(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="about-vtkfortran" tabindex="-1">About VTKFortran <a class="header-anchor" href="#about-vtkfortran" aria-label="Permalink to &quot;About VTKFortran&quot;">​</a></h1><p><strong>VTKFortran</strong> is a pure Fortran 2003+ library for writing (and reading) data files conforming the <a href="http://www.vtk.org/" target="_blank" rel="noreferrer">VTK standard</a>. It is not a wrapper around the VTK C++ source — it is an independent, pure-Fortran exporter/importer of the VTK data format, designed for Fortran programmers who want to use VTK-based visualization tools (such as <a href="https://www.paraview.org/" target="_blank" rel="noreferrer">ParaView</a>) without mixing languages.</p><p>Key properties:</p><ul><li><strong>Pure Fortran 2003+</strong> — no C or C++ dependencies</li><li><strong>Thread and processor safe</strong> — multiple files can be written concurrently under OpenMP or MPI</li><li><strong>Multiple output formats</strong> — ASCII, binary (Base64), and raw binary appended</li><li><strong>OOP design</strong> — a polymorphic <code>xml_writer</code> component is selected at runtime based on the chosen format</li></ul><h2 id="why-vtkfortran" tabindex="-1">Why VTKFortran? <a class="header-anchor" href="#why-vtkfortran" aria-label="Permalink to &quot;Why VTKFortran?&quot;">​</a></h2><p>Fortran remains the language of choice for high-performance scientific computing. Many HPC codes produce large multi-dimensional arrays that need post-processing and visualization. The VTK XML format is the native input format for ParaView, one of the most widely used open-source visualization tools. VTKFortran provides a direct path from Fortran arrays to VTK XML files without leaving the Fortran ecosystem.</p><h2 id="authors" tabindex="-1">Authors <a class="header-anchor" href="#authors" aria-label="Permalink to &quot;Authors&quot;">​</a></h2><ul><li>Stefano Zaghi — <a href="https://github.com/szaghi" target="_blank" rel="noreferrer">@szaghi</a></li></ul><p>Contributions are welcome — see the <a href="./contributing.html">Contributing</a> page.</p><h2 id="copyrights" tabindex="-1">Copyrights <a class="header-anchor" href="#copyrights" aria-label="Permalink to &quot;Copyrights&quot;">​</a></h2><p>VTKFortran is distributed under a multi-licensing system:</p><table tabindex="0"><thead><tr><th>Use case</th><th>License</th></tr></thead><tbody><tr><td>FOSS projects</td><td><a href="http://www.gnu.org/licenses/gpl-3.0.html" target="_blank" rel="noreferrer">GPL v3</a></td></tr><tr><td>Closed source / commercial</td><td><a href="http://opensource.org/licenses/BSD-2-Clause" target="_blank" rel="noreferrer">BSD 2-Clause</a></td></tr><tr><td>Closed source / commercial</td><td><a href="http://opensource.org/licenses/BSD-3-Clause" target="_blank" rel="noreferrer">BSD 3-Clause</a></td></tr><tr><td>Closed source / commercial</td><td><a href="http://opensource.org/licenses/MIT" target="_blank" rel="noreferrer">MIT</a></td></tr></tbody></table><blockquote><p>Anyone interested in using, developing, or contributing to VTKFortran is welcome — pick the license that best fits your needs.</p></blockquote>',13)])])}const g=r(n,[["render",i]]);export{p as __pageData,g as default};
